#[derive(Clone, Debug, Serialize)]
struct RuntimeRootDerivedFieldCommitProfileSample {
    path: String,
    kind: String,
    elapsed_ms: f64,
    materialized: bool,
    changed_read_count: usize,
}

fn record_root_commit_profile_sample(
    samples: &mut Vec<RuntimeRootDerivedFieldCommitProfileSample>,
    sample: RuntimeRootDerivedFieldCommitProfileSample,
) {
    const LIMIT: usize = 32;
    samples.push(sample);
    samples.sort_by(|left, right| {
        right
            .elapsed_ms
            .partial_cmp(&left.elapsed_ms)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    samples.truncate(LIMIT);
}

