#[derive(Clone, Debug, Deserialize, Serialize)]
pub struct RuntimeSourceUnit {
    pub path: String,
    pub source: String,
}

#[derive(Clone)]
struct CachedRuntimePlan {
    parsed: Arc<ParsedProgram>,
    compiled: Arc<CompiledProgram>,
}

fn runtime_plan_cache() -> &'static Mutex<BTreeMap<String, CachedRuntimePlan>> {
    static CACHE: OnceLock<Mutex<BTreeMap<String, CachedRuntimePlan>>> = OnceLock::new();
    CACHE.get_or_init(|| Mutex::new(BTreeMap::new()))
}

fn cached_runtime_plan_from_source(
    source_label: &str,
    source_text: &str,
) -> RuntimeResult<CachedRuntimePlan> {
    Ok(cached_runtime_plan_from_source_profiled(source_label, source_text)?.0)
}

fn cached_runtime_plan_from_source_profiled(
    source_label: &str,
    source_text: &str,
) -> RuntimeResult<(CachedRuntimePlan, JsonValue)> {
    let total_started = Instant::now();
    let key = sha256_bytes(source_text.as_bytes());
    if let Some(plan) = runtime_plan_cache()
        .lock()
        .ok()
        .and_then(|cache| cache.get(&key).cloned())
    {
        return Ok((
            plan,
            json!({
                "cache_hit": true,
                "total_ms": runtime_elapsed_ms(total_started)
            }),
        ));
    }

    let compiler_output = compile_source_text_to_runtime_ir(source_label, source_text)?;
    let compile_started = Instant::now();
    let compiled = CompiledProgram::from_compiler_runtime_program(compiler_output.runtime_program)?;
    let compile_ms = runtime_elapsed_ms(compile_started);
    let mut load_pipeline_profile = compiler_output.load_pipeline_profile;
    if let Some(profile) = load_pipeline_profile.as_object_mut() {
        profile.insert("compile_ms".to_owned(), json!(compile_ms));
        profile.insert("runtime_program_build_ms".to_owned(), json!(compile_ms));
        profile.insert(
            "total_ms".to_owned(),
            json!(runtime_elapsed_ms(total_started)),
        );
    }
    let plan = CachedRuntimePlan {
        parsed: Arc::new(compiler_output.parsed),
        compiled: Arc::new(compiled),
    };
    if let Ok(mut cache) = runtime_plan_cache().lock() {
        cache.insert(key, plan.clone());
    }
    Ok((plan, load_pipeline_profile))
}

fn cached_runtime_plan_from_project(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<CachedRuntimePlan> {
    Ok(cached_runtime_plan_from_project_profiled(source_label, units)?.0)
}

fn cached_full_runtime_plan_from_project(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<CachedRuntimePlan> {
    Ok(cached_full_runtime_plan_from_project_profiled(source_label, units)?.0)
}

fn cached_full_runtime_plan_from_project_profiled(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<(CachedRuntimePlan, JsonValue)> {
    let total_started = Instant::now();
    if units.len() == 1 {
        let unit = &units[0];
        let key = format!("full:{}", sha256_bytes(unit.source.as_bytes()));
        if let Some(plan) = runtime_plan_cache()
            .lock()
            .ok()
            .and_then(|cache| cache.get(&key).cloned())
        {
            return Ok((
                plan,
                json!({
                    "cache_hit": true,
                    "surface": "full-ir",
                    "total_ms": runtime_elapsed_ms(total_started)
                }),
            ));
        }
        let compiler_output = compile_source_text_to_full_ir(&unit.path, &unit.source)?;
        let compile_started = Instant::now();
        let compiled =
            CompiledProgram::from_compiler_runtime_program(compiler_output.runtime_program)?;
        let compile_ms = runtime_elapsed_ms(compile_started);
        let mut load_pipeline_profile = compiler_output.load_pipeline_profile;
        if let Some(profile) = load_pipeline_profile.as_object_mut() {
            profile.insert("compile_ms".to_owned(), json!(compile_ms));
            profile.insert("runtime_program_build_ms".to_owned(), json!(compile_ms));
            profile.insert(
                "total_ms".to_owned(),
                json!(runtime_elapsed_ms(total_started)),
            );
        }
        let plan = CachedRuntimePlan {
            parsed: Arc::new(compiler_output.parsed),
            compiled: Arc::new(compiled),
        };
        if let Ok(mut cache) = runtime_plan_cache().lock() {
            cache.insert(key, plan.clone());
        }
        return Ok((plan, load_pipeline_profile));
    }
    let key = format!("full:{}", source_units_hash(units));
    if let Some(plan) = runtime_plan_cache()
        .lock()
        .ok()
        .and_then(|cache| cache.get(&key).cloned())
    {
        return Ok((
            plan,
            json!({
                "cache_hit": true,
                "surface": "full-ir",
                "source_unit_count": units.len(),
                "total_ms": runtime_elapsed_ms(total_started)
            }),
        ));
    }
    let compiler_units = compiler_source_units_from_runtime_units(units);
    let compiler_output = compile_source_units_to_full_ir(source_label, &compiler_units)?;
    let compile_started = Instant::now();
    let compiled = CompiledProgram::from_compiler_runtime_program(compiler_output.runtime_program)?;
    let compile_ms = runtime_elapsed_ms(compile_started);
    let mut load_pipeline_profile = compiler_output.load_pipeline_profile;
    if let Some(profile) = load_pipeline_profile.as_object_mut() {
        profile.insert("compile_ms".to_owned(), json!(compile_ms));
        profile.insert("runtime_program_build_ms".to_owned(), json!(compile_ms));
        profile.insert(
            "total_ms".to_owned(),
            json!(runtime_elapsed_ms(total_started)),
        );
    }
    let plan = CachedRuntimePlan {
        parsed: Arc::new(compiler_output.parsed),
        compiled: Arc::new(compiled),
    };
    if let Ok(mut cache) = runtime_plan_cache().lock() {
        cache.insert(key, plan.clone());
    }
    Ok((plan, load_pipeline_profile))
}

fn cached_runtime_plan_from_project_profiled(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<(CachedRuntimePlan, JsonValue)> {
    let total_started = Instant::now();
    if units.len() == 1 {
        let unit = &units[0];
        return cached_runtime_plan_from_source_profiled(&unit.path, &unit.source);
    }
    let key = source_units_hash(units);
    if let Some(plan) = runtime_plan_cache()
        .lock()
        .ok()
        .and_then(|cache| cache.get(&key).cloned())
    {
        return Ok((
            plan,
            json!({
                "cache_hit": true,
                "source_unit_count": units.len(),
                "total_ms": runtime_elapsed_ms(total_started)
            }),
        ));
    }

    let compiler_units = compiler_source_units_from_runtime_units(units);
    let compiler_output = compile_source_units_to_runtime_ir(source_label, &compiler_units)?;
    let compile_started = Instant::now();
    let compiled = CompiledProgram::from_compiler_runtime_program(compiler_output.runtime_program)?;
    let compile_ms = runtime_elapsed_ms(compile_started);
    let mut load_pipeline_profile = compiler_output.load_pipeline_profile;
    if let Some(profile) = load_pipeline_profile.as_object_mut() {
        profile.insert("compile_ms".to_owned(), json!(compile_ms));
        profile.insert("runtime_program_build_ms".to_owned(), json!(compile_ms));
        profile.insert(
            "total_ms".to_owned(),
            json!(runtime_elapsed_ms(total_started)),
        );
    }
    let plan = CachedRuntimePlan {
        parsed: Arc::new(compiler_output.parsed),
        compiled: Arc::new(compiled),
    };
    if let Ok(mut cache) = runtime_plan_cache().lock() {
        cache.insert(key, plan.clone());
    }
    Ok((plan, load_pipeline_profile))
}

fn runtime_elapsed_ms(start: Instant) -> f64 {
    start.elapsed().as_secs_f64() * 1000.0
}

fn saturating_f64_sub(left: f64, right: f64) -> f64 {
    (left - right).max(0.0)
}

fn runtime_function_call_profiling_enabled() -> bool {
    cfg!(test)
        || std::env::var("BOON_RUNTIME_FUNCTION_PROFILING")
            .map(|value| {
                let value = value.trim().to_ascii_lowercase();
                !matches!(value.as_str(), "" | "0" | "false" | "off" | "no")
            })
            .unwrap_or(false)
}

fn extend_sample_limit<T>(target: &mut Vec<T>, values: Vec<T>, limit: usize) {
    for value in values {
        if target.len() >= limit {
            break;
        }
        target.push(value);
    }
}

pub fn source_units_hash(units: &[RuntimeSourceUnit]) -> String {
    if let [unit] = units {
        return sha256_bytes(unit.source.as_bytes());
    }
    let mut canonical = String::new();
    for unit in units {
        canonical.push_str(&unit.path);
        canonical.push('\0');
        canonical.push_str(&sha256_bytes(unit.source.as_bytes()));
        canonical.push('\0');
    }
    sha256_bytes(canonical.as_bytes())
}

fn compiler_source_units_from_runtime_units(
    units: &[RuntimeSourceUnit],
) -> Vec<CompilerSourceUnit> {
    units
        .iter()
        .map(|unit| CompilerSourceUnit {
            path: unit.path.clone(),
            source: unit.source.clone(),
        })
        .collect()
}

pub fn cached_static_analysis_from_project(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<RuntimeStaticProgramAnalysis> {
    let plan = cached_full_runtime_plan_from_project(source_label, units)?;
    plan.compiled
        .static_analysis
        .clone()
        .ok_or_else(|| "compiled runtime plan has no compiler static analysis".into())
}

pub fn cached_runtime_static_analysis_from_project(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<RuntimeStaticProgramAnalysis> {
    let plan = cached_runtime_plan_from_project(source_label, units)?;
    plan.compiled
        .static_analysis
        .clone()
        .ok_or_else(|| "compiled runtime plan has no compiler static analysis".into())
}

pub fn static_analysis_has_world_or_manufacturing_output_root(
    analysis: &RuntimeStaticProgramAnalysis,
) -> bool {
    analysis.output_roots.iter().any(|output| {
        matches!(output.output_kind.as_str(), "world" | "manufacturing")
            || matches!(output.root.as_str(), "world" | "manufacturing")
    })
}

pub fn project_has_world_or_manufacturing_output_root(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<bool> {
    let analysis = cached_runtime_static_analysis_from_project(source_label, units)?;
    Ok(static_analysis_has_world_or_manufacturing_output_root(
        &analysis,
    ))
}

fn cached_runtime_parsed_project(
    source_label: &str,
    units: &[RuntimeSourceUnit],
) -> RuntimeResult<Arc<ParsedProgram>> {
    Ok(Arc::clone(
        &cached_runtime_plan_from_project(source_label, units)?.parsed,
    ))
}

fn source_row_lookup_fields_from_routes(routes: &SourceRoutePlan) -> BTreeMap<String, String> {
    routes
        .route_slots
        .iter()
        .filter_map(|route| {
            route
                .row_lookup_field
                .as_ref()
                .map(|field| (route.source.clone(), field.clone()))
        })
        .collect()
}

