#[derive(Clone, Debug, Eq, PartialEq, Serialize, Deserialize)]
pub struct BuildExecutionResult {
    pub status: String,
    pub build_file: String,
    pub project_root: String,
    pub write_output: bool,
    pub icons_directory: String,
    pub output_file: String,
    pub output_binding: String,
    pub operator_evidence: Vec<String>,
    pub input_files: Vec<String>,
    pub input_byte_reads: Vec<BuildInputByteRead>,
    pub output_sha256: String,
    pub output_bytes: usize,
    pub written_files: Vec<String>,
    pub logs: Vec<BuildLogEntry>,
}

#[derive(Clone, Debug, Eq, PartialEq, Serialize, Deserialize)]
pub struct BuildInputByteRead {
    pub path: String,
    pub byte_len: usize,
    pub sha256: String,
    pub decoded_as: String,
}

#[derive(Clone, Debug, Eq, PartialEq, Serialize, Deserialize)]
pub struct BuildLogEntry {
    pub level: String,
    pub message: String,
}

pub fn run_project_build_file(
    project_root: &Path,
    build_file: &Path,
    write_output: bool,
) -> RuntimeResult<BuildExecutionResult> {
    let root = canonical_existing_dir(project_root)?;
    let build_path = sandbox_existing_file(&root, build_file)?;
    let source = fs::read_to_string(&build_path)?;
    let operator_evidence = physical_asset_build_operator_evidence(&source);
    let missing = required_physical_asset_build_operators()
        .into_iter()
        .filter(|operator| !operator_evidence.iter().any(|seen| seen == operator))
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(format!(
            "build file `{}` is missing required operators: {}",
            build_path.display(),
            missing.join(", ")
        )
        .into());
    }

    let icons_directory = build_text_binding(&source, "icons_directory")
        .ok_or("BUILD.bn does not define `icons_directory: TEXT { ... }`")?;
    let output_file = build_text_binding(&source, "output_file")
        .ok_or("BUILD.bn does not define `output_file: TEXT { ... }`")?;
    let output_binding = build_output_binding(&source).unwrap_or_else(|| "icon".to_owned());
    let icons_dir = sandbox_existing_dir(&root, Path::new(&icons_directory))?;
    let output_path = sandbox_output_file(&root, Path::new(&output_file))?;

    let mut icon_files = fs::read_dir(&icons_dir)?
        .map(|entry| entry.map(|entry| entry.path()))
        .collect::<Result<Vec<_>, _>>()?;
    icon_files.retain(|path| {
        path.extension()
            .and_then(|extension| extension.to_str())
            .is_some_and(|extension| extension.eq_ignore_ascii_case("svg"))
    });
    icon_files.sort_by_key(|path| path.strip_prefix(&root).unwrap_or(path).to_path_buf());

    let mut icon_entries = String::new();
    let mut input_byte_reads = Vec::new();
    for (index, path) in icon_files.iter().enumerate() {
        let stem = path
            .file_stem()
            .and_then(|stem| stem.to_str())
            .ok_or_else(|| format!("asset path `{}` has no UTF-8 file stem", path.display()))?;
        let svg_bytes = fs::read(path)?;
        let input_path = repo_relative_or_display(&root, path);
        input_byte_reads.push(BuildInputByteRead {
            path: input_path,
            byte_len: svg_bytes.len(),
            sha256: sha256_bytes(&svg_bytes),
            decoded_as: "Utf8".to_owned(),
        });
        let svg = String::from_utf8(svg_bytes)
            .map_err(|_| format!("asset `{}` is not valid UTF-8", path.display()))?;
        icon_entries.push_str(&format!(
            "        {stem}: TEXT {{\n            data:image/svg+xml;utf8,{}\n        }}\n",
            build_url_encode(svg.trim_end())
        ));
        if index + 1 < icon_files.len() {
            icon_entries.push('\n');
        }
    }

    let generated = format!(
        "-- GENERATED CODE - DO NOT EDIT\n-- Generated by BUILD.bn from assets/icons/\n-- Generated at: 2025-01-01T00:00:00Z\n\nFUNCTION {output_binding}() {{\n    [\n{icon_entries}    ]\n}}\n"
    );
    if write_output {
        if let Some(parent) = output_path.parent() {
            fs::create_dir_all(parent)?;
        }
        fs::write(&output_path, generated.as_bytes())?;
    }
    let input_files = icon_files
        .iter()
        .map(|path| repo_relative_or_display(&root, path))
        .collect::<Vec<_>>();
    let output_sha256 = sha256_bytes(generated.as_bytes());
    let mut logs = Vec::new();
    logs.push(BuildLogEntry {
        level: "info".to_owned(),
        message: format!("Included {} icons", icon_files.len()),
    });
    Ok(BuildExecutionResult {
        status: "pass".to_owned(),
        build_file: repo_relative_or_display(&root, &build_path),
        project_root: root.display().to_string(),
        write_output,
        icons_directory,
        output_file: output_file.clone(),
        output_binding,
        operator_evidence,
        input_files,
        input_byte_reads,
        output_sha256,
        output_bytes: generated.len(),
        written_files: if write_output {
            vec![repo_relative_or_display(&root, &output_path)]
        } else {
            Vec::new()
        },
        logs,
    })
}

pub fn generated_output_for_project_build_file(
    project_root: &Path,
    build_file: &Path,
) -> RuntimeResult<String> {
    let result = run_project_build_file(project_root, build_file, false)?;
    let root = canonical_existing_dir(project_root)?;
    let output_path = sandbox_output_file(&root, Path::new(&result.output_file))?;
    let expected = fs::read_to_string(output_path)?;
    let expected_hash = sha256_bytes(expected.as_bytes());
    if result.output_sha256 != expected_hash {
        return Err(format!(
            "BUILD.bn output hash {} does not match checked generated file hash {}",
            result.output_sha256, expected_hash
        )
        .into());
    }
    Ok(expected)
}

fn canonical_existing_dir(path: &Path) -> RuntimeResult<PathBuf> {
    let canonical = path.canonicalize()?;
    if !canonical.is_dir() {
        return Err(format!("`{}` is not a directory", path.display()).into());
    }
    Ok(canonical)
}

fn sandbox_existing_dir(root: &Path, path: &Path) -> RuntimeResult<PathBuf> {
    let resolved = sandbox_join(root, path)?;
    let canonical = resolved.canonicalize()?;
    if !canonical.starts_with(root) || !canonical.is_dir() {
        return Err(format!(
            "build directory `{}` escapes project root `{}`",
            path.display(),
            root.display()
        )
        .into());
    }
    Ok(canonical)
}

fn sandbox_existing_file(root: &Path, path: &Path) -> RuntimeResult<PathBuf> {
    let resolved = sandbox_join(root, path)?;
    let canonical = resolved.canonicalize()?;
    if !canonical.starts_with(root) || !canonical.is_file() {
        return Err(format!(
            "build file `{}` escapes project root `{}`",
            path.display(),
            root.display()
        )
        .into());
    }
    Ok(canonical)
}

fn sandbox_output_file(root: &Path, path: &Path) -> RuntimeResult<PathBuf> {
    let resolved = sandbox_join(root, path)?;
    let parent = resolved
        .parent()
        .ok_or_else(|| format!("output path `{}` has no parent", path.display()))?;
    let canonical_parent = parent.canonicalize()?;
    if !canonical_parent.starts_with(root) {
        return Err(format!(
            "build output `{}` escapes project root `{}`",
            path.display(),
            root.display()
        )
        .into());
    }
    Ok(resolved)
}

fn sandbox_join(root: &Path, path: &Path) -> RuntimeResult<PathBuf> {
    if path.is_absolute() {
        return Err(format!("build path `{}` must be project-relative", path.display()).into());
    }
    let mut resolved = root.to_path_buf();
    for component in path.components() {
        match component {
            std::path::Component::CurDir => {}
            std::path::Component::Normal(part) => resolved.push(part),
            std::path::Component::ParentDir => {
                return Err(format!(
                    "build path `{}` may not contain parent-directory segments",
                    path.display()
                )
                .into());
            }
            std::path::Component::RootDir | std::path::Component::Prefix(_) => {
                return Err(format!("build path `{}` is not relative", path.display()).into());
            }
        }
    }
    Ok(resolved)
}

fn read_plan_host_file_bytes(root: &Path, path: &str) -> RuntimeResult<Vec<u8>> {
    let root = canonical_existing_dir(root)?;
    let path = Path::new(path);
    if path.is_absolute() {
        return Err(format!(
            "host file path `{}` must be source-relative",
            path.display()
        )
        .into());
    }
    let mut resolved = root.clone();
    for component in path.components() {
        match component {
            std::path::Component::CurDir => {}
            std::path::Component::Normal(part) => resolved.push(part),
            std::path::Component::ParentDir => {
                return Err(format!(
                    "host file path `{}` may not contain parent-directory segments",
                    path.display()
                )
                .into());
            }
            std::path::Component::RootDir | std::path::Component::Prefix(_) => {
                return Err(format!(
                    "host file path `{}` must be source-relative",
                    path.display()
                )
                .into());
            }
        }
    }
    let canonical = resolved.canonicalize()?;
    if !canonical.starts_with(&root) || !canonical.is_file() {
        return Err(format!(
            "host file path `{}` escapes source root `{}`",
            path.display(),
            root.display()
        )
        .into());
    }
    Ok(fs::read(canonical)?)
}

struct PlanHostFileWrite {
    path: String,
    artifact_path: PathBuf,
    byte_len: u64,
    sha256: String,
    first_byte: u64,
    last_byte: u64,
}

impl PlanHostFileWrite {
    fn report_json(&self) -> JsonValue {
        json!({
            "kind": "file_write_bytes",
            "status": "pass",
            "mode": "typed-machine-plan-host-file-write-v1",
            "path": self.path,
            "artifact_path": self.artifact_path.display().to_string(),
            "byte_len": self.byte_len,
            "sha256": self.sha256,
            "first_byte": self.first_byte,
            "last_byte": self.last_byte,
            "write_mode": "create_or_truncate",
            "verified_after_write": true,
            "public_inline_bytes_absent": true
        })
    }
}

fn write_plan_host_file_bytes(
    root: &Path,
    path: &str,
    bytes: &[u8],
) -> RuntimeResult<PlanHostFileWrite> {
    let root = canonical_existing_dir(root)?;
    let path_ref = Path::new(path);
    if path_ref.as_os_str().is_empty() || path_ref.is_absolute() {
        return Err(format!(
            "host file path `{}` must be a non-empty source-relative path",
            path_ref.display()
        )
        .into());
    }
    let mut resolved = root.clone();
    for component in path_ref.components() {
        match component {
            std::path::Component::CurDir => {}
            std::path::Component::Normal(part) => resolved.push(part),
            std::path::Component::ParentDir => {
                return Err(format!(
                    "host file path `{}` may not contain parent-directory segments",
                    path_ref.display()
                )
                .into());
            }
            std::path::Component::RootDir | std::path::Component::Prefix(_) => {
                return Err(format!(
                    "host file path `{}` must be source-relative",
                    path_ref.display()
                )
                .into());
            }
        }
    }
    let parent = resolved
        .parent()
        .ok_or_else(|| format!("host file path `{}` has no parent", path_ref.display()))?;
    let canonical_parent = parent.canonicalize()?;
    if !canonical_parent.starts_with(&root) || !canonical_parent.is_dir() {
        return Err(format!(
            "host file path `{}` escapes source root `{}`",
            path_ref.display(),
            root.display()
        )
        .into());
    }
    if let Ok(metadata) = fs::symlink_metadata(&resolved) {
        if metadata.file_type().is_symlink() {
            return Err(format!(
                "host file path `{}` may not target a symlink",
                path_ref.display()
            )
            .into());
        }
        if metadata.is_dir() {
            return Err(format!(
                "host file path `{}` targets a directory",
                path_ref.display()
            )
            .into());
        }
    }
    let target_name = resolved
        .file_name()
        .and_then(|name| name.to_str())
        .ok_or_else(|| {
            format!(
                "host file path `{}` has no UTF-8 file name",
                path_ref.display()
            )
        })?;
    let temp_suffix = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or_default();
    let temp_path = canonical_parent.join(format!(
        ".{target_name}.boon-write-{}-{temp_suffix}.tmp",
        std::process::id()
    ));
    {
        let mut temp_file = fs::OpenOptions::new()
            .write(true)
            .create_new(true)
            .open(&temp_path)?;
        temp_file.write_all(bytes)?;
        temp_file.sync_all()?;
    }
    fs::rename(&temp_path, &resolved)?;
    let canonical_target = resolved.canonicalize()?;
    if !canonical_target.starts_with(&root) || !canonical_target.is_file() {
        return Err(format!(
            "host file path `{}` escapes source root `{}` after write",
            path_ref.display(),
            root.display()
        )
        .into());
    }
    let readback = fs::read(&canonical_target)?;
    if readback != bytes {
        return Err(format!(
            "host file path `{}` readback did not match written bytes",
            path_ref.display()
        )
        .into());
    }
    Ok(PlanHostFileWrite {
        path: path.to_owned(),
        artifact_path: canonical_target,
        byte_len: readback.len() as u64,
        sha256: sha256_bytes(&readback),
        first_byte: readback.first().copied().unwrap_or_default() as u64,
        last_byte: readback.last().copied().unwrap_or_default() as u64,
    })
}

fn repo_relative_or_display(root: &Path, path: &Path) -> String {
    path.strip_prefix(root)
        .unwrap_or(path)
        .display()
        .to_string()
}

fn required_physical_asset_build_operators() -> Vec<&'static str> {
    vec![
        "Directory/entries",
        "File/read_bytes",
        "Bytes/to_text",
        "File/write_text",
        "Url/encode",
        "Text/join_lines",
        "List/retain",
        "List/sort_by",
        "List/map",
        "Build/succeed",
        "Build/fail",
        "FLUSH",
    ]
}

fn physical_asset_build_operator_evidence(source: &str) -> Vec<String> {
    required_physical_asset_build_operators()
        .into_iter()
        .filter(|operator| source.contains(operator))
        .map(str::to_owned)
        .collect()
}

fn build_text_binding(source: &str, name: &str) -> Option<String> {
    let prefix = format!("{name}:");
    for line in source.lines() {
        let trimmed = line.trim();
        let Some(rest) = trimmed.strip_prefix(&prefix) else {
            continue;
        };
        let rest = rest.trim();
        let value = rest
            .strip_prefix("TEXT {")?
            .strip_suffix('}')?
            .trim()
            .to_owned();
        return Some(value);
    }
    None
}

fn build_output_binding(source: &str) -> Option<String> {
    source.lines().find_map(|line| {
        let trimmed = line.trim();
        let name = trimmed.strip_suffix(": [")?;
        (!name.is_empty()
            && name
                .chars()
                .all(|character| character == '_' || character.is_ascii_alphanumeric()))
        .then(|| name.to_owned())
    })
}

fn build_url_encode(input: &str) -> String {
    let mut output = String::new();
    for byte in input.bytes() {
        if byte.is_ascii_alphanumeric() || matches!(byte, b'-' | b'_' | b'.' | b'~' | b'/') {
            output.push(byte as char);
        } else {
            output.push_str(&format!("%{byte:02X}"));
        }
    }
    output
}

pub fn example_paths(name: &str) -> RuntimeResult<(PathBuf, PathBuf, PathBuf)> {
    let requested = if name == "todo" { "todomvc" } else { name };
    if !requested
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '-')
    {
        return Err(format!("invalid example name `{name}`").into());
    }
    let entry = example_manifest_entry(requested)?;
    let source = resolve_repo_file(&entry.source);
    let scenario = resolve_repo_file(&entry.scenario);
    let budget = resolve_repo_file(&entry.budget);
    for required in [&source, &scenario, &budget] {
        if !required.exists() {
            return Err(format!(
                "example `{requested}` is missing required file `{}`",
                required.display()
            )
            .into());
        }
    }
    Ok((source, scenario, budget))
}

fn resolve_repo_file(relative: impl AsRef<Path>) -> PathBuf {
    let relative = relative.as_ref();
    if relative.exists() {
        return relative.to_path_buf();
    }
    if let Ok(cwd) = std::env::current_dir() {
        for ancestor in cwd.ancestors() {
            let candidate = ancestor.join(relative);
            if candidate.exists() {
                return candidate;
            }
        }
    }
    relative.to_path_buf()
}

