impl SourceRouteListRemove {
    fn from_artifact(value: &JsonValue, context: &str) -> RuntimeResult<Self> {
        let object = artifact_object(value, context)?;
        Ok(Self {
            list: artifact_string_field(object, "list", context)?,
            predicate: RuntimeListPredicate::from_artifact(
                artifact_field(object, "predicate", context)?,
                &format!("{context}.predicate"),
            )?,
        })
    }
}

impl SourceAction {
    fn from_artifact(value: &JsonValue, context: &str) -> RuntimeResult<Self> {
        let object = artifact_object(value, context)?;
        match artifact_string_field(object, "kind", context)?.as_str() {
            "root_scalar" => Ok(Self::RootScalar),
            "derived_text" => Ok(Self::DerivedText {
                target: artifact_string_field(object, "target", context)?,
            }),
            "router_route" => Ok(Self::RouterRoute {
                target: artifact_string_field(object, "target", context)?,
                path: artifact_string_field(object, "path", context)?,
            }),
            "root_text_transform" => Ok(Self::RootTextTransform {
                target: artifact_string_field(object, "target", context)?,
                value: field_value_from_artifact(
                    artifact_field(object, "value", context)?,
                    &format!("{context}.value"),
                )?,
            }),
            "list_remove" => Ok(Self::ListRemove {
                list: artifact_string_field(object, "list", context)?,
            }),
            "list_append" => Ok(Self::ListAppend {
                list: artifact_string_field(object, "list", context)?,
                trigger: artifact_string_field(object, "trigger", context)?,
                append_ordinal: artifact_usize_field(object, "append_ordinal", context)?,
            }),
            "indexed_text" => Ok(Self::IndexedText {
                kind: SourceRouteTextAction::from_artifact(
                    &artifact_string_field(object, "text_action", context)?,
                    &format!("{context}.text_action"),
                )?,
                target: artifact_string_field(object, "target", context)?,
                guard: update_guard_from_artifact(
                    object.get("guard"),
                    &format!("{context}.guard"),
                )?,
            }),
            "indexed_bool" => Ok(Self::IndexedBool {
                kind: SourceRouteBoolAction::from_artifact(
                    &artifact_string_field(object, "bool_action", context)?,
                    &format!("{context}.bool_action"),
                )?,
                target: artifact_string_field(object, "target", context)?,
                guard: update_guard_from_artifact(
                    object.get("guard"),
                    &format!("{context}.guard"),
                )?,
            }),
            "indexed_value" => Ok(Self::IndexedValue {
                target: artifact_string_field(object, "target", context)?,
                guard: update_guard_from_artifact(
                    object.get("guard"),
                    &format!("{context}.guard"),
                )?,
            }),
            other => Err(format!("{context}.kind has unsupported value `{other}`").into()),
        }
    }
}

impl SourceRouteTextAction {
    fn from_artifact(value: &str, context: &str) -> RuntimeResult<Self> {
        match value {
            "indexed_text_const" => Ok(Self::Const),
            "indexed_text_source_text" => Ok(Self::SourceText),
            "indexed_text_previous_value" => Ok(Self::PreviousValue),
            "indexed_text_read_path" => Ok(Self::ReadPath),
            "indexed_text_trim_or_previous" => Ok(Self::TextTrimOrPrevious),
            "indexed_text_computed" => Ok(Self::Computed),
            other => Err(format!("{context} has unsupported value `{other}`").into()),
        }
    }
}

impl SourceRouteBoolAction {
    fn from_artifact(value: &str, context: &str) -> RuntimeResult<Self> {
        match value {
            "indexed_bool_not" => Ok(Self::BoolNot),
            "indexed_bool_const_true" => Ok(Self::ConstTrue),
            "indexed_bool_const_false" => Ok(Self::ConstFalse),
            "indexed_bool_read_path" => Ok(Self::ReadPath),
            "indexed_bool_source_pulse" => Ok(Self::SourcePulse),
            "indexed_bool_match" => Ok(Self::Match),
            other => Err(format!("{context} has unsupported value `{other}`").into()),
        }
    }
}

fn field_value_artifact(value: &FieldValue) -> JsonValue {
    match value {
        FieldValue::Text(value) => json!({ "kind": "text", "value": value }),
        FieldValue::Bool(value) => json!({ "kind": "bool", "value": value }),
        FieldValue::Enum(value) => json!({ "kind": "enum", "value": value }),
        FieldValue::Bytes(value) => json!({ "kind": "bytes", "value": value.artifact_json() }),
        FieldValue::Json(value) => json!({ "kind": "json", "value": value }),
    }
}

fn field_value_from_artifact(value: &JsonValue, context: &str) -> RuntimeResult<FieldValue> {
    let object = artifact_object(value, context)?;
    match artifact_string_field(object, "kind", context)?.as_str() {
        "text" => Ok(FieldValue::Text(artifact_string_field(
            object, "value", context,
        )?)),
        "bool" => Ok(FieldValue::Bool(artifact_bool_field(
            object, "value", context,
        )?)),
        "enum" => Ok(FieldValue::Enum(artifact_string_field(
            object, "value", context,
        )?)),
        "bytes" => Ok(FieldValue::Bytes(RuntimeBytes::from_artifact(
            artifact_field(object, "value", context)?,
            &format!("{context}.value"),
        )?)),
        "json" => Ok(FieldValue::Json(
            artifact_field(object, "value", context)?.clone(),
        )),
        other => Err(format!("{context}.kind has unsupported value `{other}`").into()),
    }
}

fn optional_field_value_from_artifact(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<Option<FieldValue>> {
    let Some(value) = object.get(key) else {
        return Ok(None);
    };
    if value.is_null() {
        return Ok(None);
    }
    Ok(Some(field_value_from_artifact(
        value,
        &format!("{context}.{key}"),
    )?))
}

fn list_source_binding_plan_artifact(plan: &ListSourceBindingPlan) -> JsonValue {
    json!({
        "list_slots": plan.list_slots.iter().map(list_source_binding_slot_artifact).collect::<Vec<_>>()
    })
}

impl ListSourceBindingPlan {
    fn from_artifact(value: &JsonValue) -> RuntimeResult<Self> {
        let context = "runtime_plan.list_source_bindings";
        let object = artifact_object(value, context)?;
        let list_slots = artifact_array_field(object, "list_slots", context)?
            .iter()
            .enumerate()
            .map(|(index, value)| {
                ListSourceBindingSlot::from_artifact(
                    value,
                    &format!("{context}.list_slots[{index}]"),
                )
            })
            .collect::<RuntimeResult<Vec<_>>>()?;
        let mut lists = BTreeSet::new();
        for slot in &list_slots {
            if !lists.insert(slot.list.as_str()) {
                return Err(format!("{context}.list_slots duplicate list `{}`", slot.list).into());
            }
        }
        Ok(Self { list_slots })
    }
}

fn list_source_binding_slot_artifact(slot: &ListSourceBindingSlot) -> JsonValue {
    json!({
        "list": slot.list,
        "row_scope": slot.row_scope,
        "source_paths": slot.source_paths
    })
}

impl ListSourceBindingSlot {
    fn from_artifact(value: &JsonValue, context: &str) -> RuntimeResult<Self> {
        let object = artifact_object(value, context)?;
        let source_paths = artifact_string_array_field(object, "source_paths", context)?;
        if source_paths.is_empty() {
            return Err(format!("{context}.source_paths must not be empty").into());
        }
        ensure_unique_strings(&source_paths, &format!("{context}.source_paths"))?;
        Ok(Self {
            list: artifact_string_field(object, "list", context)?,
            row_scope: artifact_string_field(object, "row_scope", context)?,
            source_paths,
        })
    }
}

fn artifact_object<'a>(
    value: &'a JsonValue,
    context: &str,
) -> RuntimeResult<&'a serde_json::Map<String, JsonValue>> {
    value
        .as_object()
        .ok_or_else(|| format!("{context} is not an object").into())
}

fn artifact_array<'a>(value: &'a JsonValue, context: &str) -> RuntimeResult<&'a Vec<JsonValue>> {
    value
        .as_array()
        .ok_or_else(|| format!("{context} is not an array").into())
}

fn artifact_field<'a>(
    object: &'a serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<&'a JsonValue> {
    object
        .get(key)
        .ok_or_else(|| format!("{context} missing `{key}`").into())
}

fn artifact_array_field<'a>(
    object: &'a serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<&'a Vec<JsonValue>> {
    artifact_array(
        artifact_field(object, key, context)?,
        &format!("{context}.{key}"),
    )
}

fn artifact_string_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<String> {
    artifact_field(object, key, context)?
        .as_str()
        .map(str::to_owned)
        .ok_or_else(|| format!("{context}.{key} is not a string").into())
}

fn optional_string_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<Option<String>> {
    let Some(value) = object.get(key) else {
        return Ok(None);
    };
    if value.is_null() {
        return Ok(None);
    }
    value
        .as_str()
        .map(|value| Some(value.to_owned()))
        .ok_or_else(|| format!("{context}.{key} is not a string or null").into())
}

fn optional_usize_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<Option<usize>> {
    let Some(value) = object.get(key) else {
        return Ok(None);
    };
    if value.is_null() {
        return Ok(None);
    }
    let value = value
        .as_u64()
        .ok_or_else(|| format!("{context}.{key} is not a non-negative integer or null"))?;
    Ok(Some(usize::try_from(value).map_err(|_| {
        format!("{context}.{key} does not fit in usize")
    })?))
}

fn artifact_string_array_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<Vec<String>> {
    artifact_array_field(object, key, context)?
        .iter()
        .enumerate()
        .map(|(index, value)| {
            value
                .as_str()
                .map(str::to_owned)
                .ok_or_else(|| format!("{context}.{key}[{index}] is not a string").into())
        })
        .collect()
}

fn artifact_string_map_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<BTreeMap<String, String>> {
    let map = artifact_field(object, key, context)?
        .as_object()
        .ok_or_else(|| format!("{context}.{key} is not an object"))?;
    map.iter()
        .map(|(name, value)| {
            Ok((
                name.clone(),
                value
                    .as_str()
                    .map(str::to_owned)
                    .ok_or_else(|| format!("{context}.{key}.{name} is not a string"))?,
            ))
        })
        .collect()
}

fn artifact_string_set_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<BTreeSet<String>> {
    let values = artifact_string_array_field(object, key, context)?;
    ensure_unique_strings(&values, &format!("{context}.{key}"))?;
    Ok(values.into_iter().collect())
}

fn ensure_unique_strings(values: &[String], context: &str) -> RuntimeResult<()> {
    let mut seen = BTreeSet::new();
    for value in values {
        if !seen.insert(value) {
            return Err(format!("{context} duplicates `{value}`").into());
        }
    }
    Ok(())
}

fn artifact_bool_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<bool> {
    artifact_field(object, key, context)?
        .as_bool()
        .ok_or_else(|| format!("{context}.{key} is not a bool").into())
}

fn artifact_i64_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<i64> {
    artifact_field(object, key, context)?
        .as_i64()
        .ok_or_else(|| format!("{context}.{key} is not an i64").into())
}

fn artifact_usize_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<usize> {
    let value = artifact_field(object, key, context)?
        .as_u64()
        .ok_or_else(|| format!("{context}.{key} is not a non-negative integer"))?;
    usize::try_from(value).map_err(|_| format!("{context}.{key} does not fit in usize").into())
}

fn artifact_u64_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<u64> {
    artifact_field(object, key, context)?
        .as_u64()
        .ok_or_else(|| format!("{context}.{key} is not a non-negative integer").into())
}

fn artifact_usize_map_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    context: &str,
) -> RuntimeResult<BTreeMap<String, usize>> {
    let map = artifact_field(object, key, context)?
        .as_object()
        .ok_or_else(|| format!("{context}.{key} is not an object"))?;
    map.iter()
        .map(|(name, value)| {
            let count = value
                .as_u64()
                .ok_or_else(|| format!("{context}.{key}.{name} is not a non-negative integer"))?;
            Ok((
                name.clone(),
                usize::try_from(count)
                    .map_err(|_| format!("{context}.{key}.{name} does not fit in usize"))?,
            ))
        })
        .collect()
}

fn artifact_count_matches(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    actual: usize,
    context: &str,
) -> RuntimeResult<()> {
    let expected = artifact_usize_field(object, key, context)?;
    if expected == actual {
        Ok(())
    } else {
        Err(format!("{context}.{key} expected {expected}, decoded {actual}").into())
    }
}

fn artifact_pointer_usize(value: &JsonValue, pointer: &str, context: &str) -> RuntimeResult<usize> {
    let value = value
        .pointer(pointer)
        .ok_or_else(|| format!("compiled artifact missing {context}"))?
        .as_u64()
        .ok_or_else(|| format!("compiled artifact {context} is not a non-negative integer"))?;
    usize::try_from(value)
        .map_err(|_| format!("compiled artifact {context} does not fit in usize").into())
}

fn artifact_len_matches(
    actual: usize,
    value: &JsonValue,
    pointer: &str,
    context: &str,
) -> RuntimeResult<()> {
    let expected = artifact_pointer_usize(value, pointer, context)?;
    if actual == expected {
        Ok(())
    } else {
        Err(format!("{context} expected {expected}, decoded {actual}").into())
    }
}

fn expect_artifact_string_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    expected: &str,
    context: &str,
) -> RuntimeResult<()> {
    let actual = artifact_string_field(object, key, context)?;
    if actual == expected {
        Ok(())
    } else {
        Err(format!("{context}.{key} expected `{expected}`, decoded `{actual}`").into())
    }
}

fn expect_artifact_bool_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    expected: bool,
    context: &str,
) -> RuntimeResult<()> {
    let actual = artifact_bool_field(object, key, context)?;
    if actual == expected {
        Ok(())
    } else {
        Err(format!("{context}.{key} expected `{expected}`, decoded `{actual}`").into())
    }
}

fn expect_artifact_string_array_field(
    object: &serde_json::Map<String, JsonValue>,
    key: &str,
    expected: &[&str],
    context: &str,
) -> RuntimeResult<()> {
    let actual = artifact_string_array_field(object, key, context)?;
    let expected = expected
        .iter()
        .map(|value| (*value).to_owned())
        .collect::<Vec<_>>();
    if actual == expected {
        Ok(())
    } else {
        Err(format!("{context}.{key} expected {expected:?}, decoded {actual:?}").into())
    }
}

#[derive(Clone, Debug)]
struct CompiledArtifact {
    body: JsonValue,
    sha256: String,
}

impl CompiledArtifact {
    const REQUIRED_SECTIONS: [&'static str; 11] = [
        "semantic_index",
        "symbol_table",
        "storage_layout",
        "source_schemas",
        "route_op_streams",
        "dependency_graph",
        "document_lowering_tables",
        "bridge_schemas",
        "compiled_schedule",
        "runtime_plan",
        "machine_plan",
    ];

    fn from_parts(
        parsed: &ParsedProgram,
        compiled: &CompiledProgram,
        program_hash: &str,
        typecheck_report_hash: &str,
        render_slot_table_hash: &str,
        machine_plan: &MachinePlan,
        machine_plan_hash: &str,
        machine_plan_verification_status: &str,
        machine_plan_verification_error_count: usize,
    ) -> Self {
        let program_metadata = compiled.source_program_metadata("compiled artifact body");
        let compiled_schedule = compiled.report();
        let source_units = compiled_artifact_source_units(parsed);
        let typecheck_metadata = compiled.source_typecheck_metadata("compiled artifact body");
        let body = json!({
            "artifact_kind": "boonc.compiled_program",
            "artifact_version": 1,
            "format": "boonc-json-v1",
            "runtime_load_mode": "compiled_static_graph_sidecar",
            "parser_ast_required_for_execution": false,
            "typed_ir_required_for_mvp_loader": false,
            "program_kind": parsed.kind.as_str(),
            "program_hash": program_hash,
            "source_unit_hashes": source_units,
            "report_schema_hash": compiled_artifact_report_schema_hash(),
            "semantic_index": program_metadata.semantic_index,
            "symbol_table": compiled_schedule["runtime_symbol_table"].clone(),
            "runtime_symbol_count": compiled_schedule["runtime_symbol_count"].clone(),
            "runtime_symbol_ownership": compiled_schedule["runtime_symbol_ownership"].clone(),
            "storage_layout": compiled_schedule["typed_storage_layout"].clone(),
            "source_schemas": {
                "source_payload_schema_count": compiled_schedule["source_payload_schema_count"].clone(),
                "source_payload_field_count": compiled_schedule["source_payload_field_count"].clone(),
                "source_payload_text_field_count": compiled_schedule["source_payload_text_field_count"].clone(),
                "source_payload_key_field_count": compiled_schedule["source_payload_key_field_count"].clone(),
                "source_payload_address_field_count": compiled_schedule["source_payload_address_field_count"].clone(),
                "source_payload_bytes_field_count": compiled_schedule["source_payload_bytes_field_count"].clone(),
                "source_payload_pointer_field_count": compiled_schedule["source_payload_pointer_field_count"].clone()
            },
            "route_op_streams": compiled_schedule["source_route_op_streams"].clone(),
            "dependency_graph": {
                "static_schedule_verified": program_metadata.static_schedule_verified,
                "hidden_identity_verified": program_metadata.hidden_identity_verified,
                "graph_node_count": program_metadata.graph_node_count,
                "schedule_node_count": compiled_schedule["schedule_node_count"].clone(),
                "source_route_count": compiled_schedule["source_route_count"].clone(),
                "list_source_binding_count": compiled_schedule["list_source_binding_count"].clone()
            },
            "document_lowering_tables": {
                "render_slot_table_hash": render_slot_table_hash,
                "typed_render_metadata_used": typecheck_metadata.typed_render_metadata_used,
                "render_slot_count": typecheck_metadata.render_slot_count,
                "render_slot_failure_count": typecheck_metadata.render_slot_failure_count
            },
            "bridge_schemas": {
                "status": "not_present_or_not_separate_from_source_payload_schemas",
                "schema_count": 0
            },
            "typecheck_report_hash": typecheck_report_hash,
            "machine_plan_hash": machine_plan_hash,
            "plan_hash": machine_plan_hash,
            "plan_version": machine_plan.version,
            "target_profile": machine_plan.target_profile.as_str(),
            "capability_summary": machine_plan.capability_summary,
            "machine_plan_verification": {
                "status": machine_plan_verification_status,
                "error_count": machine_plan_verification_error_count
            },
            "runtime_plan": compiled.runtime_plan_artifact(),
            "machine_plan": machine_plan,
            "compiled_schedule": compiled_schedule
        });
        let bytes =
            serde_json::to_vec_pretty(&body).expect("compiled artifact JSON must serialize");
        let sha256 = sha256_bytes(&bytes);
        Self { body, sha256 }
    }

    fn load_from_path(path: &Path) -> RuntimeResult<Self> {
        let bytes = fs::read(path)?;
        let sha256 = sha256_bytes(&bytes);
        let body: JsonValue = serde_json::from_slice(&bytes)?;
        let artifact = Self { body, sha256 };
        artifact.validate(path)?;
        Ok(artifact)
    }

    fn runtime_generic_derived_plan(&self) -> RuntimeResult<RuntimeGenericDerivedPlan> {
        RuntimeGenericDerivedPlan::from_artifact(
            self.body
                .get("runtime_plan")
                .and_then(|plan| plan.get("generic_derived"))
                .ok_or("compiled artifact missing runtime_plan.generic_derived")?,
        )
    }

    fn runtime_storage_initialization_plan(
        &self,
    ) -> RuntimeResult<RuntimeStorageInitializationPlan> {
        RuntimeStorageInitializationPlan::from_artifact(
            self.body
                .get("runtime_plan")
                .and_then(|plan| plan.get("storage_initialization"))
                .ok_or("compiled artifact missing runtime_plan.storage_initialization")?,
        )
    }

    fn runtime_document_lowering_tables(&self) -> RuntimeResult<RuntimeDocumentLoweringTables> {
        RuntimeDocumentLoweringTables::from_artifact(
            self.body
                .get("runtime_plan")
                .and_then(|plan| plan.get("document_lowering"))
                .ok_or("compiled artifact missing runtime_plan.document_lowering")?,
        )
    }

    fn runtime_non_route_tables(&self) -> RuntimeResult<RuntimeNonRouteTables> {
        RuntimeNonRouteTables::from_artifact_body(&self.body)
    }

    fn runtime_source_routes(&self) -> RuntimeResult<SourceRoutePlan> {
        SourceRoutePlan::from_artifact_body(&self.body)
    }

    fn machine_plan(&self) -> RuntimeResult<MachinePlan> {
        serde_json::from_value(
            self.body
                .get("machine_plan")
                .cloned()
                .ok_or("compiled artifact missing machine_plan")?,
        )
        .map_err(|error| format!("compiled artifact machine_plan did not decode: {error}").into())
    }

    fn validate(&self, path: &Path) -> RuntimeResult<()> {
        if self.body.get("artifact_kind").and_then(JsonValue::as_str)
            != Some("boonc.compiled_program")
        {
            return Err(format!("{} is not a Boon compiled artifact", path.display()).into());
        }
        if self.body.get("format").and_then(JsonValue::as_str) != Some("boonc-json-v1") {
            return Err(format!("{} compiled artifact has wrong format", path.display()).into());
        }
        if self
            .body
            .get("artifact_version")
            .and_then(JsonValue::as_u64)
            != Some(1)
        {
            return Err(format!("{} compiled artifact has wrong version", path.display()).into());
        }
        if self
            .body
            .get("parser_ast_required_for_execution")
            .and_then(JsonValue::as_bool)
            != Some(false)
        {
            return Err(format!(
                "{} compiled artifact must not require parser AST for execution",
                path.display()
            )
            .into());
        }
        if self
            .body
            .get("typed_ir_required_for_mvp_loader")
            .and_then(JsonValue::as_bool)
            != Some(false)
        {
            return Err(format!(
                "{} compiled artifact must not require typed IR for the MVP loader",
                path.display()
            )
            .into());
        }
        for key in [
            "runtime_load_mode",
            "program_hash",
            "source_unit_hashes",
            "report_schema_hash",
            "typecheck_report_hash",
            "machine_plan_hash",
        ] {
            if self.body.get(key).is_none() {
                return Err(format!("{} compiled artifact missing `{key}`", path.display()).into());
            }
        }
        for key in Self::REQUIRED_SECTIONS {
            if self.body.get(key).is_none() {
                return Err(format!(
                    "{} compiled artifact missing section `{key}`",
                    path.display()
                )
                .into());
            }
        }
        self.validate_partial_runtime_plan(path)?;
        self.validate_machine_plan(path)?;
        Ok(())
    }

    fn validate_machine_plan(&self, path: &Path) -> RuntimeResult<()> {
        let plan = self.machine_plan()?;
        let canonical_plan = serde_json::to_value(&plan).map_err(|error| {
            format!(
                "{} embedded machine_plan could not reserialize canonically: {error}",
                path.display()
            )
        })?;
        if self.body.get("machine_plan") != Some(&canonical_plan) {
            return Err(format!(
                "{} embedded machine_plan contains unknown or non-canonical fields",
                path.display()
            )
            .into());
        }
        let actual_hash = plan_sha256(&plan)?;
        let expected_hash = self
            .body
            .get("machine_plan_hash")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| format!("{} machine_plan_hash is not a string", path.display()))?;
        if actual_hash != expected_hash {
            return Err(format!(
                "{} machine_plan_hash mismatch: expected {expected_hash}, got {actual_hash}",
                path.display()
            )
            .into());
        }
        if self.body.get("plan_hash").and_then(JsonValue::as_str) != Some(expected_hash) {
            return Err(
                format!("{} plan_hash must match machine_plan_hash", path.display()).into(),
            );
        }
        if self.body.get("target_profile").and_then(JsonValue::as_str)
            != Some(plan.target_profile.as_str())
        {
            return Err(format!(
                "{} target_profile must match embedded machine_plan",
                path.display()
            )
            .into());
        }
        if self.body.get("capability_summary")
            != Some(&serde_json::to_value(&plan.capability_summary)?)
        {
            return Err(format!(
                "{} capability_summary must match embedded machine_plan",
                path.display()
            )
            .into());
        }
        let verification = verify_plan(&plan)?;
        if verification.status != "pass" {
            return Err(format!(
                "{} embedded machine_plan verification failed with {} error(s)",
                path.display(),
                verification.error_count
            )
            .into());
        }
        Ok(())
    }

    fn validate_partial_runtime_plan(&self, path: &Path) -> RuntimeResult<()> {
        let plan = self
            .body
            .get("runtime_plan")
            .and_then(JsonValue::as_object)
            .ok_or_else(|| format!("{} runtime_plan is not an object", path.display()))?;
        for key in [
            "runtime_plan_version",
            "format",
            "ast_free",
            "source_free_runtime_instantiation_ready",
            "runtime_instantiation_blocked_by",
            "included_runtime_owned_sections",
            "excluded_parser_ast_sections",
            "runtime_symbols",
            "scalar_equations",
            "derived_text_transforms",
            "list_equations",
            "list_projections",
            "source_routes",
            "list_source_bindings",
            "generic_derived",
            "storage_initialization",
            "document_lowering",
        ] {
            if !plan.contains_key(key) {
                return Err(format!("{} runtime_plan missing `{key}`", path.display()).into());
            }
        }
        if plan.get("runtime_plan_version").and_then(JsonValue::as_u64) != Some(1) {
            return Err(format!("{} runtime_plan has wrong version", path.display()).into());
        }
        if plan.get("format").and_then(JsonValue::as_str) != Some("boonc-runtime-plan-json-v1") {
            return Err(format!("{} runtime_plan has wrong format", path.display()).into());
        }
        if plan.get("ast_free").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!("{} runtime_plan must be AST-free", path.display()).into());
        }
        if plan
            .get("source_free_runtime_instantiation_ready")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} runtime_plan must claim source-free instantiation readiness",
                path.display()
            )
            .into());
        }
        if plan
            .get("runtime_instantiation_blocked_by")
            .and_then(JsonValue::as_array)
            .is_none_or(|blockers| !blockers.is_empty())
        {
            return Err(format!(
                "{} runtime_plan must not list runtime instantiation blockers",
                path.display()
            )
            .into());
        }
        let included = plan
            .get("included_runtime_owned_sections")
            .and_then(JsonValue::as_object)
            .ok_or_else(|| {
                format!(
                    "{} runtime_plan included_runtime_owned_sections is not an object",
                    path.display()
                )
            })?;
        for key in [
            "runtime_symbols",
            "scalar_equations",
            "derived_text_transforms",
            "list_equations",
            "list_projections",
            "source_routes",
            "list_source_bindings",
            "runtime_storage_initialization_plan",
            "document_lowering_runtime_tables",
            "root_state_paths",
            "list_summary_fields",
            "dynamic_list_view_lists",
            "source_route_payload_fields",
            "generic_derived_partial_ast_free_plan",
        ] {
            if included.get(key).and_then(JsonValue::as_bool) != Some(true) {
                return Err(format!(
                    "{} runtime_plan included_runtime_owned_sections `{key}` is not true",
                    path.display()
                )
                .into());
            }
        }
        if plan
            .get("runtime_symbols")
            .and_then(JsonValue::as_object)
            .and_then(|symbols| symbols.get("paths"))
            .and_then(JsonValue::as_array)
            .is_none_or(Vec::is_empty)
        {
            return Err(format!("{} runtime_plan has no runtime symbols", path.display()).into());
        }
        if plan
            .get("source_routes")
            .and_then(JsonValue::as_object)
            .and_then(|routes| routes.get("route_slots"))
            .and_then(JsonValue::as_array)
            .is_none()
        {
            return Err(
                format!("{} runtime_plan has no source route slots", path.display()).into(),
            );
        }
        let generic_derived = plan
            .get("generic_derived")
            .and_then(JsonValue::as_object)
            .ok_or_else(|| {
                format!(
                    "{} runtime_plan generic_derived is not an object",
                    path.display()
                )
            })?;
        if generic_derived.get("format").and_then(JsonValue::as_str)
            != Some("boonc-runtime-generic-derived-partial-json-v1")
        {
            return Err(format!(
                "{} runtime_plan generic_derived has wrong format",
                path.display()
            )
            .into());
        }
        if generic_derived
            .get("generic_derived_runtime_ast_free")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} runtime_plan generic_derived must be AST-free",
                path.display()
            )
            .into());
        }
        for key in ["root_fields", "indexed_fields"] {
            if generic_derived
                .get(key)
                .and_then(JsonValue::as_array)
                .is_none()
            {
                return Err(format!(
                    "{} runtime_plan generic_derived missing array `{key}`",
                    path.display()
                )
                .into());
            }
        }
        if generic_derived
            .get("unsupported_reasons")
            .and_then(JsonValue::as_object)
            .is_none()
        {
            return Err(format!(
                "{} runtime_plan generic_derived missing unsupported_reasons",
                path.display()
            )
            .into());
        }
        for key in [
            "root_field_count",
            "indexed_field_count",
            "root_supported_count",
            "indexed_supported_count",
        ] {
            if generic_derived
                .get(key)
                .and_then(JsonValue::as_u64)
                .is_none()
            {
                return Err(format!(
                    "{} runtime_plan generic_derived missing count `{key}`",
                    path.display()
                )
                .into());
            }
        }
        let storage = plan
            .get("storage_initialization")
            .and_then(JsonValue::as_object)
            .ok_or_else(|| {
                format!(
                    "{} runtime_plan storage_initialization is not an object",
                    path.display()
                )
            })?;
        if storage.get("format").and_then(JsonValue::as_str)
            != Some("boonc-runtime-storage-initialization-json-v1")
        {
            return Err(format!(
                "{} runtime_plan storage_initialization has wrong format",
                path.display()
            )
            .into());
        }
        if storage
            .get("storage_runtime_ast_free")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} runtime_plan storage_initialization must be AST-free",
                path.display()
            )
            .into());
        }
        for key in [
            "root_slots",
            "root_initial_field_copies",
            "list_slots",
            "indexed_row_initial_resets",
        ] {
            if storage.get(key).and_then(JsonValue::as_array).is_none() {
                return Err(format!(
                    "{} runtime_plan storage_initialization missing array `{key}`",
                    path.display()
                )
                .into());
            }
        }
        let document_lowering = plan
            .get("document_lowering")
            .and_then(JsonValue::as_object)
            .ok_or_else(|| {
                format!(
                    "{} runtime_plan document_lowering is not an object",
                    path.display()
                )
            })?;
        if document_lowering.get("format").and_then(JsonValue::as_str)
            != Some("boonc-document-lowering-runtime-tables-json-v1")
        {
            return Err(format!(
                "{} runtime_plan document_lowering has wrong format",
                path.display()
            )
            .into());
        }
        if document_lowering
            .get("document_lowering_runtime_ast_free")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} runtime_plan document_lowering must be AST-free",
                path.display()
            )
            .into());
        }
        for key in [
            "root_summary_paths",
            "list_summary_fields",
            "dynamic_list_view_lists",
            "render_slots",
            "unresolved_projection_storage_paths",
        ] {
            if document_lowering
                .get(key)
                .and_then(JsonValue::as_array)
                .is_none()
            {
                return Err(format!(
                    "{} runtime_plan document_lowering missing array `{key}`",
                    path.display()
                )
                .into());
            }
        }
        for key in [
            "summary_limits",
            "projection_storage_resolutions",
            "render_patch_lowering",
        ] {
            if document_lowering
                .get(key)
                .and_then(JsonValue::as_object)
                .is_none()
            {
                return Err(format!(
                    "{} runtime_plan document_lowering missing object `{key}`",
                    path.display()
                )
                .into());
            }
        }
        Ok(())
    }

    fn report(&self) -> JsonValue {
        json!({
            "artifact_kind": "boonc.compiled_program",
            "artifact_version": self.body["artifact_version"].clone(),
            "format": self.body["format"].clone(),
            "sha256": self.sha256,
            "program_hash": self.body["program_hash"].clone(),
            "report_schema_hash": self.body["report_schema_hash"].clone(),
            "machine_plan_hash": self.body["machine_plan_hash"].clone(),
            "plan_hash": self.body["plan_hash"].clone(),
            "target_profile": self.body["target_profile"].clone(),
            "capability_summary": self.body["capability_summary"].clone(),
            "machine_plan_verification": self.body["machine_plan_verification"].clone(),
            "parser_ast_required_for_execution": self.body["parser_ast_required_for_execution"].clone(),
            "typed_ir_required_for_mvp_loader": self.body["typed_ir_required_for_mvp_loader"].clone(),
            "source_unit_count": self
                .body
                .get("source_unit_hashes")
                .and_then(JsonValue::as_array)
                .map_or(0, Vec::len),
            "semantic_index_version": self.body["semantic_index"]["version"].clone(),
            "runtime_symbol_count": self.body["runtime_symbol_count"].clone(),
            "source_route_count": self.body["compiled_schedule"]["source_route_count"].clone(),
            "source_route_op_stream_count": self.body["compiled_schedule"]["source_route_op_stream_count"].clone(),
            "storage_layout": self.body["storage_layout"].clone(),
            "bridge_schema_count": self.body["bridge_schemas"]["schema_count"].clone()
        })
    }

    fn report_with_path(&self, path: &Path) -> JsonValue {
        let mut report = self.report();
        report["path"] = json!(path.display().to_string());
        report
    }

    fn missing_runtime_plan_sections(&self) -> Vec<&'static str> {
        self.body
            .get("runtime_plan")
            .and_then(|plan| plan.get("runtime_instantiation_blocked_by"))
            .and_then(JsonValue::as_array)
            .map(|sections| {
                sections
                    .iter()
                    .filter_map(JsonValue::as_str)
                    .filter_map(|section| match section {
                        "generic_derived_ast_free_plan" => Some("generic_derived_ast_free_plan"),
                        "runtime_storage_initialization_plan" => {
                            Some("runtime_storage_initialization_plan")
                        }
                        "document_lowering_runtime_tables" => {
                            Some("document_lowering_runtime_tables")
                        }
                        _ => None,
                    })
                    .collect()
            })
            .unwrap_or_else(|| {
                vec![
                    "runtime_plan",
                    "generic_derived_ast_free_plan",
                    "runtime_storage_initialization_plan",
                    "document_lowering_runtime_tables",
                ]
            })
    }

    fn section_presence(&self) -> JsonValue {
        let mut sections = serde_json::Map::new();
        for key in Self::REQUIRED_SECTIONS {
            sections.insert(key.to_owned(), json!(self.body.get(key).is_some()));
        }
        JsonValue::Object(sections)
    }
}

fn compiled_artifact_source_units(parsed: &ParsedProgram) -> Vec<JsonValue> {
    parsed
        .files
        .iter()
        .map(|file| {
            json!({
                "path": file.path,
                "start_line": file.start_line,
                "module": file.module,
                "source_hash": sha256_bytes(file.source.as_bytes()),
                "source_bytes": file.source.len()
            })
        })
        .collect()
}

fn compiled_artifact_report_schema_hash() -> String {
    report_schema_hash()
}

