#[derive(Clone, Debug, Eq, PartialEq)]
struct DirtyKeyEntry {
    list_id: String,
    field_id: String,
    key: u64,
}

#[derive(Clone, Debug, Default)]
struct DirtyKeySets {
    entries: DirtyKeyEntries,
}

impl DirtyKeySets {
    fn with_capacity(capacity: usize) -> Self {
        Self {
            entries: DirtyKeyEntries::with_capacity(capacity),
        }
    }

    fn clear(&mut self) {
        self.entries.clear();
    }

    fn mark(&mut self, list_id: &str, field_id: &str, key: u64) {
        let entry = DirtyKeyEntry {
            list_id: list_id.to_owned(),
            field_id: field_id.to_owned(),
            key,
        };
        if !self.entries.contains(&entry) {
            self.entries.push(entry);
        }
    }

    fn mark_delta(&mut self, delta: &SemanticDelta<'_>) {
        let Some(list_id) = delta.list_id.as_ref() else {
            return;
        };
        let Some(key) = delta.key else {
            return;
        };
        let field_id = delta
            .field_path
            .as_ref()
            .map_or(delta.kind, |field| field.as_ref());
        self.mark(list_id.as_ref(), field_id, key);
    }

    fn mark_deltas(&mut self, deltas: &[SemanticDelta<'_>]) -> usize {
        self.clear();
        for delta in deltas {
            self.mark_delta(delta);
        }
        self.key_count()
    }

    fn mark_indexes(&mut self, list_id: &str, field_id: &str, indexes: &[usize]) {
        self.clear();
        for index in indexes {
            self.mark(list_id, field_id, *index as u64 + 1);
        }
    }

    fn key_count(&self) -> usize {
        let mut count = 0usize;
        for (index, entry) in self.entries.iter().enumerate() {
            if !self.entries[..index]
                .iter()
                .any(|previous| previous.list_id == entry.list_id && previous.key == entry.key)
            {
                count += 1;
            }
        }
        count
    }

    fn duplicate_attempt_count(&self) -> usize {
        self.entries.len().saturating_sub(self.key_count())
    }

    fn metrics(
        &self,
        density_denominator: usize,
        fanout_recompute_candidate_count: usize,
        top_recompute_causes: Vec<String>,
    ) -> RuntimeDirtySetMetrics {
        let unique_key_count = self.key_count();
        let duplicate_attempt_count = self.entries.len().saturating_sub(unique_key_count);
        let density_estimate = if density_denominator == 0 {
            0.0
        } else {
            unique_key_count as f64 / density_denominator as f64
        };
        let (recommended_representation, recommendation_reason) =
            dirty_set_recommendation(unique_key_count, duplicate_attempt_count, density_estimate);
        RuntimeDirtySetMetrics {
            entry_count: self.entries.len(),
            unique_key_count,
            duplicate_attempt_count,
            fanout_recompute_candidate_count,
            density_estimate,
            top_recompute_causes,
            representation_boundary: "DirtyKeySets",
            recommended_representation,
            recommendation_reason,
        }
    }
}

fn dirty_set_recommendation(
    unique_key_count: usize,
    duplicate_attempt_count: usize,
    density_estimate: f64,
) -> (&'static str, String) {
    if unique_key_count == 0 {
        return (
            "current_vec",
            "no dirty keyed rows observed; current empty Vec path is cheapest".to_owned(),
        );
    }
    if density_estimate >= 0.25 {
        return (
            "fixed_bitset",
            format!(
                "dirty density {:.3} is high enough that indexed bitsets should beat sparse key scans",
                density_estimate
            ),
        );
    }
    if unique_key_count >= 4096 && density_estimate <= 0.05 {
        return (
            "roaring_bitmap",
            format!(
                "{} sparse dirty keys at density {:.3} may benefit from compressed bitmap chunks",
                unique_key_count, density_estimate
            ),
        );
    }
    if duplicate_attempt_count > unique_key_count / 4 {
        return (
            "sorted_vec",
            format!(
                "{} duplicate dirty attempts over {} unique keys suggest sort/dedup before fanout",
                duplicate_attempt_count, unique_key_count
            ),
        );
    }
    (
        "current_vec",
        format!(
            "{} unique dirty keys at density {:.3} keep the current small Vec path reasonable",
            unique_key_count, density_estimate
        ),
    )
}

