#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct NumericStabilityInterval {
    min: i64,
    max: i64,
}

impl NumericStabilityInterval {
    fn all() -> Self {
        Self {
            min: i64::MIN,
            max: i64::MAX,
        }
    }

    fn contains(self, value: i64) -> bool {
        self.min <= value && value <= self.max
    }

    fn intersect(self, other: Self) -> Option<Self> {
        let min = self.min.max(other.min);
        let max = self.max.min(other.max);
        (min <= max).then_some(Self { min, max })
    }

    fn connected_union(self, other: Self) -> Option<Self> {
        let self_before_other = self.max.saturating_add(1) < other.min;
        let other_before_self = other.max.saturating_add(1) < self.min;
        if self_before_other || other_before_self {
            return None;
        }
        Some(Self {
            min: self.min.min(other.min),
            max: self.max.max(other.max),
        })
    }
}

fn merge_connected_numeric_stability_guards(
    previous: Option<BTreeMap<GenericReadKey, NumericStabilityInterval>>,
    mut current: BTreeMap<GenericReadKey, NumericStabilityInterval>,
) -> BTreeMap<GenericReadKey, NumericStabilityInterval> {
    let Some(previous) = previous else {
        return current;
    };
    for (read, interval) in current.iter_mut() {
        if let Some(previous_interval) = previous.get(read).copied()
            && let Some(union) = previous_interval.connected_union(*interval)
        {
            *interval = union;
        }
    }
    current
}

