#[derive(Clone, Debug, PartialEq)]
enum BoonValue {
    Empty,
    Text(String),
    Enum(String),
    Number(i64),
    Bool(bool),
    Bytes(RuntimeBytes),
    Record(BTreeMap<String, BoonValue>),
    RecordColumns(ValueColumns),
    List(Vec<BoonValue>),
    ListChunk {
        source: Box<BoonValue>,
        size: usize,
        item_field: String,
        label_field: String,
    },
    RowRef {
        list: String,
        index: usize,
    },
    ListRef(String),
    ListSelection {
        list: String,
        indices: ListSelectionIndices,
    },
    NaN,
    Error(String),
}

fn boon_value_scalar_text(value: &BoonValue) -> String {
    match value {
        BoonValue::Text(value) | BoonValue::Enum(value) => value.clone(),
        BoonValue::Number(value) => value.to_string(),
        BoonValue::Bool(true) => "True".to_owned(),
        BoonValue::Bool(false) => "False".to_owned(),
        BoonValue::Empty => String::new(),
        BoonValue::NaN => "NaN".to_owned(),
        BoonValue::Error(value) => value.clone(),
        BoonValue::Bytes(_)
        | BoonValue::Record(_)
        | BoonValue::RecordColumns(_)
        | BoonValue::List(_)
        | BoonValue::ListChunk { .. }
        | BoonValue::RowRef { .. }
        | BoonValue::ListRef(_)
        | BoonValue::ListSelection { .. } => String::new(),
    }
}

fn push_bytes_constructor_value(target: &mut Vec<u8>, value: BoonValue) -> RuntimeResult<()> {
    match value {
        BoonValue::Number(value) if (0..=255).contains(&value) => {
            target.push(value as u8);
            Ok(())
        }
        BoonValue::Number(value) => Err(format!(
            "BYTES constructor expected BYTE in range 0..255, got number {value}"
        )
        .into()),
        BoonValue::Bytes(value) => match value.payload {
            RuntimeBytesPayload::Inline(bytes) | RuntimeBytesPayload::Shared(bytes) => {
                target.extend_from_slice(bytes.as_ref());
                Ok(())
            }
            RuntimeBytesPayload::BlobRef { .. } | RuntimeBytesPayload::PageRef { .. } => Err(
                "BYTES constructor cannot inline blob/page-backed BYTES in the legacy evaluator"
                    .into(),
            ),
        },
        other => Err(format!(
            "BYTES constructor expected BYTE or BYTES item, got {}",
            boon_value_kind_label(&other)
        )
        .into()),
    }
}

fn finish_bytes_constructor(
    size: &BytesSizeSyntax,
    item_count: usize,
    mut bytes: Vec<u8>,
) -> RuntimeResult<BoonValue> {
    if let BytesSizeSyntax::Fixed(expected) = size {
        if item_count == 0 && *expected > 0 {
            bytes.resize(*expected, 0);
        } else if bytes.len() != *expected {
            return Err(format!(
                "BYTES[{expected}] contains {} byte(s); fixed BYTES length must match exactly",
                bytes.len()
            )
            .into());
        }
    }
    Ok(BoonValue::Bytes(RuntimeBytes::inline(Bytes::from(bytes))))
}

fn boon_value_kind_label(value: &BoonValue) -> &'static str {
    match value {
        BoonValue::Empty => "EMPTY",
        BoonValue::Text(_) => "TEXT",
        BoonValue::Enum(_) => "ENUM",
        BoonValue::Number(_) => "NUMBER",
        BoonValue::Bool(_) => "BOOL",
        BoonValue::Bytes(_) => "BYTES",
        BoonValue::Record(_) | BoonValue::RecordColumns(_) => "RECORD",
        BoonValue::List(_)
        | BoonValue::ListChunk { .. }
        | BoonValue::ListRef(_)
        | BoonValue::ListSelection { .. } => "LIST",
        BoonValue::RowRef { .. } => "ROW",
        BoonValue::NaN => "NaN",
        BoonValue::Error(_) => "ERROR",
    }
}

fn is_generic_render_constructor(function: &str) -> bool {
    matches!(
        function,
        "Document/new"
            | "Element/container"
            | "Element/stripe"
            | "Element/text"
            | "Element/label"
            | "Element/paragraph"
            | "Element/link"
            | "Element/button"
            | "Element/checkbox"
            | "Element/text_input"
            | "Scene/new"
            | "Scene/Element/stripe"
            | "Scene/Element/block"
            | "Scene/Element/text"
            | "Scene/Element/text_input"
            | "Scene/Element/checkbox"
            | "Scene/Element/label"
            | "Scene/Element/button"
            | "Scene/Element/paragraph"
            | "Scene/Element/link"
    )
}

fn is_generic_world_constructor(function: &str) -> bool {
    matches!(
        function,
        "World/new"
            | "World/camera"
            | "World/perspective_camera"
            | "World/light"
            | "World/point_light"
            | "World/material"
            | "World/transform"
            | "World/primitive"
            | "World/indexed_mesh"
            | "World/model"
            | "World/group"
            | "Camera/perspective"
            | "Light/directional"
            | "World/instance"
    )
}

fn is_generic_solid_constructor(function: &str) -> bool {
    matches!(
        function,
        "Assembly/new"
            | "Part/new"
            | "Part/instance"
            | "Solid/box"
            | "Solid/rounded_box"
            | "Solid/sphere"
            | "Solid/cylinder"
            | "Solid/cone"
            | "Solid/torus"
            | "Solid/extrude"
            | "Solid/revolve"
            | "Solid/loft"
            | "Solid/shell"
            | "Solid/union"
            | "Solid/difference"
            | "Solid/translate"
    )
}

fn runtime_generic_constructor_accepts_children(function: &str) -> bool {
    is_generic_render_constructor(function)
        || is_generic_world_constructor(function)
        || is_generic_solid_constructor(function)
        || is_light_constructor(function)
}

fn boon_value_is_generic_render_constructor(value: &BoonValue) -> bool {
    let BoonValue::Record(fields) = value else {
        return false;
    };
    fields
        .get("constructor")
        .and_then(BoonValue::as_text)
        .is_some_and(|constructor| is_generic_render_constructor(&constructor))
}

fn is_light_constructor(function: &str) -> bool {
    matches!(
        function,
        "Light/directional" | "Light/ambient" | "Light/spot"
    )
}

